import{_ as s,o as a,c as t,ag as n}from"./chunks/framework.C9sp7nFj.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"PanSave","text":"一站式网盘媒体自动化管理平台","tagline":"自部署在 NAS、家用服务器或云主机上，把 Telegram 频道扫描、榜单追更、豆瓣求片、Emby 缺集、网盘转存和通知提醒串成一套可长期运行的媒体管理流程。","image":{"src":"/images/hero.svg","alt":"PanSave"},"actions":[{"theme":"brand","text":"快速开始","link":"/guide/getting-started"},{"theme":"alt","text":"Docker 部署","link":"/guide/deploy/docker"},{"theme":"alt","text":"使用帮助","link":"/guide/"}]},"features":[{"icon":"📡","title":"频道扫描与转存","details":"扫描 Telegram 频道里的网盘分享，按你的网盘账号和整理目录执行直连转存。"},{"icon":"🎬","title":"榜单与监控清单","details":"从 TMDB、豆瓣、猫眼等榜单加入监控，持续寻找新资源和缺失资源。"},{"icon":"📝","title":"豆瓣求片","details":"读取豆瓣片单，把用户想看的电影和剧集转成可跟踪、可通知的求片任务。"},{"icon":"🧭","title":"Emby 缺集扫描","details":"扫描媒体库里缺少的剧集，并把缺集条目加入监控，后续继续补找。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1780491682000}'),i={name:"index.md"};function o(r,e,d,l,c,p){return a(),t("div",null,[...e[0]||(e[0]=[n('<section class="home-section"><div class="home-section-header"><p>使用流程</p><h2>从发现资源到确认入库，尽量少做重复手工活</h2></div><div class="module-grid"><a class="module-card" href="/guide/help/system-settings"><span>1</span><strong>先完成基础配置</strong><p>配置 Telegram、网盘账号、转存目录、TMDB、Emby 和通知方式，为后续自动流程准备好账号和目标。</p></a><a class="module-card" href="/guide/help/resource-acquisition"><span>2</span><strong>选择要使用的来源</strong><p>在频道扫描、监控策略、榜单订阅和 TMDB 看板里决定哪些频道、榜单或条目需要被持续跟踪。</p></a><a class="module-card" href="/guide/help/douban-requests"><span>3</span><strong>让片单变成求片任务</strong><p>把豆瓣片单里的需求同步进系统，先查 Emby，再按监控来源搜索和转存。</p></a><a class="module-card" href="/guide/help/emby-missing"><span>4</span><strong>用缺集扫描补漏</strong><p>定期查看 Emby 缺集扫描结果，把仍缺少的剧集加入监控，让后续流程继续补齐。</p></a></div></section><section class="home-section"><div class="home-section-header"><p>适用场景</p><h2>适合自建媒体库和网盘整理场景</h2></div><div class="module-grid"><a class="module-card" href="/guide/help/resource-acquisition#频道扫描"><span>频道</span><strong>频道里有资源，但不想每天手动翻</strong><p>维护频道后批量扫描历史消息，先看命中结果，再手动执行转存，风险可控。</p></a><a class="module-card" href="/guide/help/resource-acquisition#榜单订阅"><span>榜单</span><strong>热门榜单想持续追更</strong><p>订阅榜单后，新增条目会进入监控清单，后续按你启用的搜索来源继续寻找。</p></a><a class="module-card" href="/guide/help/douban-requests"><span>求片</span><strong>家人或朋友用豆瓣片单提需求</strong><p>每个求片用户可以维护自己的片单和通知邮箱，状态变化后按用户分发提醒。</p></a><a class="module-card" href="/guide/help/logs-notifications"><span>通知</span><strong>希望问题出现时有人提醒</strong><p>目录缺失、账号失效、容量不足、登录风险和任务完成摘要都可以通过机器人或邮件提醒。</p></a></div></section><section class="home-section home-cta"><div><p>开始使用</p><h2>从部署开始，逐步接入自己的媒体管理流程</h2><span>先完成基础配置，再按实际使用习惯开启需要的能力，让日常整理、跟踪和提醒保持在同一个管理界面里完成。</span></div><a href="/guide/getting-started">开始部署</a></section>',3)])])}const h=s(i,[["render",o]]);export{m as __pageData,h as default};
